import { useState, useRef, useEffect, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { AVAILABLE_MODELS } from "@/lib/limits";

interface AgentRunnerProps {
  agentId: string;
  slug: string;
  agentName: string;
  category: string;
  systemPrompt?: string | null;
